solution_code:
#include <iostream>

int main()
{
    int length = 0;
    int width = 0;
    std::cin >> length >> width;

    int area = length * width;
    int perimeter = 2 * (length + width);

    std::cout << area << '\n';
    std::cout << perimeter << '\n';

    return 0;
}

